import { exec, execSync } from "node:child_process";
import os from "node:os";
import readline from "node:readline";
import { reportHandoff } from "../analytics.js";
import { openChromelessWindow } from "../browser.js";
import { attachBrowserHandoffKeepalive, startBrowserHandoff, } from "../browserHandoff.js";
import { getConfig, saveCredentials } from "../config.js";
const LOGIN_TIMEOUT_MS = 10 * 60 * 1000;
const PASTE_HINT_DELAY_MS = 8 * 1000;
export function getFrontmostApp() {
    if (os.platform() !== "darwin") {
        return null;
    }
    try {
        return execSync(`osascript -e 'tell application "System Events" to get name of first process whose frontmost is true'`, { stdio: "pipe", encoding: "utf-8" }).trim();
    }
    catch {
        return null;
    }
}
export function focusApp(appName) {
    if (!appName || os.platform() !== "darwin") {
        return;
    }
    exec(`osascript -e 'tell application "${appName}" to activate'`);
}
const CALLBACK_HTML = `<html>
<body style="margin:0;background:#f8fafc;color:#0f172a;font-family:system-ui,-apple-system,sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;overflow:hidden">
  <div style="text-align:center;max-width:400px">
    <h1 style="font-size:24px;font-weight:600;margin:0 0 16px 0">Bitfab</h1>
    <p style="margin:0;color:#059669">Authenticated! You can close this window.</p>
    <button onclick="window.close()" style="margin-top:16px;padding:8px 16px;background:#0f172a;color:white;border:none;border-radius:8px;font-size:14px;font-weight:500;cursor:pointer">Close Window</button>
  </div>
</body>
</html>`;
async function verifyToken(serviceUrl, token) {
    try {
        const res = await fetch(`${serviceUrl}/api/plugin/whoami`, {
            headers: { Authorization: `Bearer ${token}` },
        });
        if (!res.ok) {
            return null;
        }
        return (await res.json());
    }
    catch {
        return null;
    }
}
/**
 * Race the browser-handoff channels (loopback + ticket) until one delivers
 * the token. Interactive terminals also get a stdin-paste racer as a
 * last resort — a no-op under piped stdin (Bash-tool agents) but useful
 * on a broken network where both channels fail.
 */
export async function runLogin(platform, pluginVersion) {
    const config = getConfig();
    const previousApp = getFrontmostApp();
    const interactive = process.stdin.isTTY === true;
    const { loopback, ticket, browserUrl } = await startBrowserHandoff({
        serviceUrl: config.serviceUrl,
        ticketKind: "auth.login",
        timeoutMs: LOGIN_TIMEOUT_MS,
        buildUrl: ({ port, ticketId }) => {
            const urlParams = new URLSearchParams();
            if (port !== null) {
                urlParams.set("callbackPort", String(port));
            }
            if (ticketId !== null) {
                urlParams.set("ticket", ticketId);
            }
            const base = `${config.serviceUrl}/plugin/auth/${platform.authPath}`;
            const qs = urlParams.toString();
            return qs ? `${base}?${qs}` : base;
        },
        loopbackRoutes: [
            {
                path: "/callback",
                handle: (params, res, resolve) => {
                    const token = params.get("token");
                    if (token) {
                        res.writeHead(200, { "Content-Type": "text/html" });
                        res.end(CALLBACK_HTML);
                        resolve({ token });
                    }
                    else {
                        res.writeHead(400, { "Content-Type": "application/json" });
                        res.end(JSON.stringify({ ok: false, error: "No token received" }));
                    }
                },
            },
        ],
    });
    console.log("\nOpening your browser to sign in...");
    console.log(`  ${browserUrl}`);
    console.log("");
    console.log("(If the browser didn't open, visit the URL above manually.)");
    openChromelessWindow(browserUrl);
    // Shared keepalive: URL redisplay at 4s, plus 30s heartbeat on piped
    // stdout so agent shell tools driving this process don't classify a
    // blocked login as idle. No backup launch — `openChromelessWindow`
    // already branches on `CODEX_SANDBOX=seatbelt` and opens a plain tab
    // up front in that environment, so there's no case where a deferred
    // duplicate tab adds value.
    const stopKeepalive = attachBrowserHandoffKeepalive({
        loopback,
        ticket,
        browserUrl,
    });
    // Interactive stdin-paste fallback: a third resolver feeding into its own
    // promise joined to the race below.
    let resolvePaste = () => { };
    let pasteDone = false;
    const pastePromise = new Promise((resolve) => {
        resolvePaste = (value) => {
            if (pasteDone) {
                return;
            }
            pasteDone = true;
            resolve(value);
        };
    });
    const rl = interactive
        ? readline.createInterface({
            input: process.stdin,
            output: process.stdout,
        })
        : null;
    const hintTimer = interactive
        ? setTimeout(() => {
            if (loopback.done || ticket.done || pasteDone) {
                return;
            }
            console.log("");
            console.log("Having trouble? If your browser shows a token, paste it here and press Enter:");
        }, PASTE_HINT_DELAY_MS)
        : null;
    rl?.on("line", async (line) => {
        if (loopback.done || ticket.done || pasteDone) {
            return;
        }
        const trimmed = line.trim();
        if (!trimmed) {
            return;
        }
        process.stdout.write("Verifying token... ");
        const who = await verifyToken(config.serviceUrl, trimmed);
        if (who) {
            console.log("ok.");
            resolvePaste({ token: trimmed });
        }
        else {
            console.log("invalid token. Try again or complete the browser flow.");
        }
    });
    const timeoutPromise = new Promise((_resolve, reject) => {
        setTimeout(() => reject(new Error("Authentication timed out after 10 minutes. Run login again.")), LOGIN_TIMEOUT_MS);
    });
    function cleanup() {
        stopKeepalive();
        if (hintTimer) {
            clearTimeout(hintTimer);
        }
        loopback.close();
        ticket.close();
        rl?.close();
    }
    const racers = [];
    if (loopback.available) {
        racers.push(loopback.promise.then((v) => ({ token: v.token, wonBy: "loopback" })));
    }
    if (ticket.available) {
        racers.push(ticket.promise.then((v) => ({ token: v.token, wonBy: "ticket" })));
    }
    if (interactive) {
        racers.push(pastePromise.then((v) => ({ token: v.token, wonBy: "paste" })));
    }
    try {
        const { token, wonBy } = await Promise.race([...racers, timeoutPromise]);
        cleanup();
        saveCredentials(token);
        const who = await verifyToken(config.serviceUrl, token);
        const greeting = who?.user.email
            ? `Logged in as ${who.user.email}.`
            : "Authentication successful.";
        console.log(`\n${greeting}`);
        console.log(`Bitfab MCP tools are now active. (via ${wonBy})`);
        await reportHandoff(token, pluginVersion, platform, {
            flow: "auth.login",
            wonBy: wonBy,
            loopbackAvailable: loopback.available,
            ticketAvailable: ticket.available,
        });
        focusApp(previousApp);
        process.exit(0);
    }
    catch (err) {
        cleanup();
        console.error(`\n${err.message}`);
        process.exit(1);
    }
}
